package com.securestack.service;import org.springframework.stereotype.*;import org.springframework.web.multipart.MultipartFile;import org.springframework.transaction.annotation.Transactional;import java.io.*;import java.util.*;import java.util.stream.*;import org.apache.commons.compress.archivers.zip.*;import com.fasterxml.jackson.databind.ObjectMapper;import com.securestack.analysis.SecurityRule;import com.securestack.analysis.ai.Ai.*;import com.securestack.dto.Dto.*;import com.securestack.model.Entities.*;import com.securestack.model.Enums.*;import com.securestack.repository.*;import com.securestack.util.Sanitizer;
@Service public class ScanService{private final List<SecurityRule> rules;private final ScanRepository scans;private final FindingRepository findings;private final AiAnalysisProvider ai;private final ObjectMapper mapper=new ObjectMapper();private final Set<String> allowed=Set.of("js","ts","tsx","java","py","json","yaml","yml","env","example","dockerfile","tf","md","txt","xml","properties","gradle","pom.xml","package.json");public ScanService(List<SecurityRule> r,ScanRepository s,FindingRepository f,AiAnalysisProvider ai){rules=r;scans=s;findings=f;this.ai=ai;}@Transactional public CreateScanResponse create(String name,String depth,String pastedJson,MultipartFile[] uploads,boolean pdf)throws Exception{List<ScanFileInput> files=new ArrayList<>();if(pastedJson!=null&&!pastedJson.isBlank()){for(PastedFile p:Arrays.asList(mapper.readValue(pastedJson,PastedFile[].class)))if(p.content()!=null&&!p.content().isBlank())files.add(new ScanFileInput(p.fileName(),p.fileType(),p.content()));}if(uploads!=null)for(MultipartFile m:uploads){if(m==null||m.isEmpty())continue;if(m.getOriginalFilename()!=null&&m.getOriginalFilename().toLowerCase().endsWith(".zip")){try(ZipArchiveInputStream zis=new ZipArchiveInputStream(m.getInputStream())){ZipArchiveEntry e;while((e=zis.getNextZipEntry())!=null){if(e.isDirectory()||skip(e.getName()))continue;String c=new String(zis.readNBytes(2_000_000));files.add(new ScanFileInput(e.getName(),type(e.getName()),c));}}}else files.add(new ScanFileInput(m.getOriginalFilename(),type(m.getOriginalFilename()),new String(m.getBytes())));}if(files.isEmpty())throw new IllegalArgumentException("At least one pasted or uploaded file is required.");if(files.size()>50)throw new IllegalArgumentException("Too many files; maximum is 50.");for(ScanFileInput f:files)validate(f);Scan scan=new Scan();scan.name=name==null||name.isBlank()?"Untitled scan":name;scan.fileCount=files.size();scan.files=files.stream().map(ScanFileInput::fileName).toList();List<Finding> fs=new ArrayList<>();for(ScanFileInput file:files)for(SecurityRule rule:rules)if(rule.supports(file))fs.addAll(rule.analyze(file));fs=sort(fs);scan.findingCount=fs.size();scan.riskScore=score(fs);scan.riskLevel=level(scan.riskScore);Map<Severity,Long> sev=fs.stream().collect(Collectors.groupingBy(f->f.severity,()->new EnumMap<>(Severity.class),Collectors.counting()));Map<Category,Long> cat=fs.stream().collect(Collectors.groupingBy(f->f.category,()->new EnumMap<>(Category.class),Collectors.counting()));var ar=ai.generateSummary(new AiAnalysisRequest(scan.name,scan.riskScore,sev,cat,depth));scan.executiveSummary=ar.executiveSummary();scan.remediationSummary=ar.remediationPlan();scans.save(scan);for(Finding f:fs){f.scanId=scan.id;findings.save(f);}return new CreateScanResponse(scan.id,scan.status,scan.riskScore,scan.riskLevel,scan.findingCount);}List<Finding> sort(List<Finding> fs){return fs.stream().sorted(Comparator.comparing((Finding f)->f.severity.ordinal()).thenComparing(f->f.confidence.ordinal()).thenComparing(f->f.category.name()).thenComparing(f->f.fileName).thenComparing(f->Optional.ofNullable(f.lineNumber).orElse(0))).toList();}public int score(List<Finding> fs){int p=fs.stream().mapToInt(f->switch(f.severity){case CRITICAL->20;case HIGH->10;case MEDIUM->5;case LOW->2;case INFO->0;}).sum();return Math.max(0,100-p);}public RiskLevel level(int s){return s>=90?RiskLevel.LOW:s>=70?RiskLevel.MODERATE:s>=40?RiskLevel.HIGH:RiskLevel.CRITICAL;}void validate(ScanFileInput f){String n=f.fileName()==null?"file.txt":f.fileName();if(f.content().length()>2_000_000)throw new IllegalArgumentException("File exceeds maximum allowed size: "+n);if(!allowed.contains(type(n))&&!n.equalsIgnoreCase("Dockerfile"))throw new IllegalArgumentException("Unsupported file type: "+n);}boolean skip(String n){String l=n.toLowerCase();return l.contains("node_modules/")||l.contains(".git/")||l.contains("target/")||l.contains("build/")||l.contains("dist/")||l.contains("venv/");}String type(String n){if(n==null)return"txt";String l=n.toLowerCase();if(l.endsWith("pom.xml"))return"pom.xml";if(l.endsWith("package.json"))return"package.json";if(l.endsWith("dockerfile")||l.equals("dockerfile"))return"dockerfile";int i=l.lastIndexOf('.');return i<0?l:l.substring(i+1);}public ScanResultDto get(UUID id){Scan s=scans.findById(id).orElseThrow();List<Finding> fs=findings.findByScanId(id);return dto(s,fs);}public List<ScanListItem> list(){return scans.findAll().stream().map(s->new ScanListItem(s.id,s.name,s.createdAt,s.riskScore,s.riskLevel,s.findingCount)).toList();}@Transactional public void update(UUID sid,UUID fid,FindingStatus st){Finding f=findings.findById(fid).orElseThrow();if(!f.scanId.equals(sid))throw new NoSuchElementException();f.status=st;}ScanResultDto dto(Scan s,List<Finding> fs){Map<Severity,Long> sev=fs.stream().collect(Collectors.groupingBy(f->f.severity,()->new EnumMap<>(Severity.class),Collectors.counting()));Map<Category,Long> cat=fs.stream().collect(Collectors.groupingBy(f->f.category,()->new EnumMap<>(Category.class),Collectors.counting()));return new ScanResultDto(s.id,s.name,s.createdAt,s.status,s.riskScore,s.riskLevel,s.fileCount,s.findingCount,s.executiveSummary,s.remediationSummary,fs.stream().map(f->new FindingDto(f.id,f.fileName,f.lineNumber,f.title,f.description,f.severity,f.category,f.confidence,f.evidence,f.recommendation,f.secureExample,f.status,f.ruleId)).toList(),sev,cat,s.files);} }
